```typescript
const PROCESSING_FEE = 5;
const BASE_PREMIUMS: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };
const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
const calculateQuotePremium = (items: any[]): number =>
  items.reduce((sum: number, item: any) => sum + itemBasePremium(item), 0) + PROCESSING_FEE;
export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => ({ premium: calculateQuotePremium(step.items) }));
  return { results };
}
```

I need to modify `calculateQuotePremium` to handle the block discount. The simplest approach: count components by type, and if exactly 3 of a type, use 60 instead of 75.

