import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === QUOTE: Base premiums ===
  it("returns premium of 5 G for an empty item list (processing fee only)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote" as const, items: [] }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("calculates base premium of 100 G + 5 G fee for a single sword", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("calculates base premium for each item type (amulet 60, staff 80, potion 40)", () => {
    const makeScenario = (type: string) => ({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote" as const, items: [{ type, material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(processScenario(makeScenario("amulet"))).toEqual({ results: [{ premium: 65 }] });
    expect(processScenario(makeScenario("staff"))).toEqual({ results: [{ premium: 85 }] });
    expect(processScenario(makeScenario("potion"))).toEqual({ results: [{ premium: 45 }] });
  });
  it("calculates base premium of 25 G per component (rune/moonstone)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it("applies building block discount: 3 alike components cost 60 G instead of 75 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("does not apply block discount for 4 alike components (block requires exactly 3)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("calculates mixed components without block (2 runes + 1 moonstone = 75 G)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 80 }] });
  });
  it("applies two separate blocks for 3 runes + 3 moonstones = 120 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 125 }] });
  });
  it("sums base premiums for multiple different items in a policy", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });

  // === QUOTE: Item-specific modifiers ===
  it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 155 }] });
  });
  it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 135 }] });
  });
  it("applies both cursed and high-enchantment surcharges to same item", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 185 }] });
  });
  it("applies item-specific surcharges only to affected items in multi-item policy", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 215 }] });
  });

  // === QUOTE: Policy-wide modifiers ===
  it("applies 10% first insurance surcharge to policy base premium", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("applies 20% loyalty discount for customers with >= 2 years");
  it.todo("applies 15% follow-up discount on second and subsequent contracts");
  it.todo("combines all modifiers: newcomer with cursed sword = 165 G");
  it.todo("combines all modifiers: long-standing customer second contract cursed enchanted sword = 160 G");

  // === QUOTE: Rounding ===
  it.todo("rounds premiums up (in MHPCO's favor)");

  // === QUOTE: Errors ===
  it.todo("rejects unknown item type with non-zero exit");

  // === CLAIM: Standard reimbursement ===
  it.todo("reimburses full damage minus 100 G deductible for regular item");
  it.todo("applies deductible per damaged item in multi-damage event");
  it.todo("reimburses component damage minus deductible");

  // === CLAIM: Special clauses ===
  it.todo("reimburses enchantment >= 8 damage at 50% then deductible");
  it.todo("reimburses dragon material damage fully then deductible");
  it.todo("when both dragon and enchantment >= 8 apply, 50% rule wins then deductible");
  it.todo("dragon material with enchantment < 8 gets full reimbursement then deductible");

  // === CLAIM: Cap ===
  it.todo("caps total payout at 2x insurance sum");
  it.todo("tracks remaining cap across multiple claims on same policy");
  it.todo("reduces payout to remaining cap when cap is nearly exhausted");

  // === CLAIM: Errors ===
  it.todo("rejects damage to item not covered by policy");
  it.todo("rejects more damage entries of a type than policy covers");
  it.todo("rejects negative damage amount");

  // === CLI integration ===
  it.todo("processes a full scenario with quote and claim steps via CLI JSON interface");
});

