The key change is in `processScenario`. Before:

```
export function processScenario(scenario: any): any {
  let quoteCount = 0;                    // 1 assignment, 1 binding, 1 constant
  const results = scenario.steps.map((step: any) => {
    const quoteIndex = quoteCount;       // 1 binding
    quoteCount++;                        // 1 assignment
    return { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex) };
  });
  return { results };
}
```

