const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isComponent = (item: any): boolean =>
  COMPONENT_TYPES.includes(item.type);

const itemBasePremium = (item: any): number =>
  BASE_PREMIUMS[item.type] ?? 0;

const itemPremiumWithModifiers = (item: any): number => {
  const base = itemBasePremium(item);
  return base
    + (item.cursed ? base * 0.5 : 0)
    + (item.enchantment >= 5 ? base * 0.3 : 0);
};

const regularItems = (items: any[]): any[] =>
  items.filter((item: any) => !isComponent(item));

const regularItemsPremium = (items: any[]): number =>
  regularItems(items)
    .reduce((sum: number, item: any) => sum + itemPremiumWithModifiers(item), 0);

const componentBlockPremium = (count: number, type: string): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];

const countByType = (items: any[]): Record<string, number> =>
  items.filter(isComponent).reduce(
    (acc: Record<string, number>, item: any) => ({
      ...acc,
      [item.type]: (acc[item.type] ?? 0) + 1,
    }),
    {},
  );

const componentsPremium = (items: any[]): number =>
  Object.entries(countByType(items)).reduce(
    (sum, [type, count]) => sum + componentBlockPremium(count, type),
    0,
  );

const policyBasePremium = (items: any[]): number =>
  regularItems(items)
    .reduce((sum: number, item: any) => sum + itemBasePremium(item), 0)
  + componentsPremium(items);

const policyWideModifierRate = (customer: any, quoteIndex: number): number =>
  0.1 + (customer.yearsWithMHPCO >= 2 ? -0.2 : 0) + (quoteIndex > 0 ? -0.15 : 0);

const KNOWN_TYPES = Object.keys(BASE_PREMIUMS);

const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): number => {
  for (const item of items) {
    if (!KNOWN_TYPES.includes(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  const itemsTotal = regularItemsPremium(items) + componentsPremium(items);
  const policyModifier = policyBasePremium(items) * policyWideModifierRate(customer, quoteIndex);
  return Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any, index: number) => ({
    premium: calculateQuotePremium(step.items, scenario.customer, index),
  }));
  return { results };
};

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === QUOTE: Base premiums ===
  it("returns premium of 5 G for an empty item list (processing fee only)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote" as const, items: [] }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("calculates base premium of 100 G + 5 G fee for a single sword", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("calculates base premium for each item type (amulet 60, staff 80, potion 40)", () => {
    const makeScenario = (type: string) => ({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote" as const, items: [{ type, material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(processScenario(makeScenario("amulet"))).toEqual({ results: [{ premium: 71 }] });
    expect(processScenario(makeScenario("staff"))).toEqual({ results: [{ premium: 93 }] });
    expect(processScenario(makeScenario("potion"))).toEqual({ results: [{ premium: 49 }] });
  });
  it("calculates base premium of 25 G per component (rune/moonstone)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "rune" },
          { type: "rune" },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("applies building block discount: 3 alike components cost 60 G instead of 75 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("does not apply block discount for 4 alike components (block requires exactly 3)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("calculates mixed components without block (2 runes + 1 moonstone = 75 G)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("applies two separate blocks for 3 runes + 3 moonstones = 120 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });
  it("sums base premiums for multiple different items in a policy", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // === QUOTE: Item-specific modifiers ===
  it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("applies both cursed and high-enchantment surcharges to same item", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });
  it("applies item-specific surcharges only to affected items in multi-item policy", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // === QUOTE: Policy-wide modifiers ===
  it("applies 10% first insurance surcharge to policy base premium", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("applies 20% loyalty discount for customers with >= 2 years", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 2 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("applies 15% follow-up discount on second and subsequent contracts", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
        {
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({
      results: [
        { premium: 115 },
        { premium: 100 },
      ],
    });
  });
  it("combines all modifiers: newcomer with cursed sword = 165 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("combines all modifiers: long-standing customer second contract cursed enchanted sword = 160 G", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
        {
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // === QUOTE: Rounding ===
  it("rounds premiums up (in MHPCO's favor)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "rune" },
        ],
      }],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // === QUOTE: Errors ===
  it("rejects unknown item type with non-zero exit", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "broomstick", material: "wood", enchantment: 0, cursed: false }],
      }],
    };
    expect(() => processScenario(scenario)).toThrow();
  });

  // === CLAIM: Standard reimbursement ===
  it.todo("reimburses full damage minus 100 G deductible for regular item");
  it.todo("applies deductible per damaged item in multi-damage event");
  it.todo("reimburses component damage minus deductible");

  // === CLAIM: Special clauses ===
  it.todo("reimburses enchantment >= 8 damage at 50% then deductible");
  it.todo("reimburses dragon material damage fully then deductible");
  it.todo("when both dragon and enchantment >= 8 apply, 50% rule wins then deductible");
  it.todo("dragon material with enchantment < 8 gets full reimbursement then deductible");

  // === CLAIM: Cap ===
  it.todo("caps total payout at 2x insurance sum");
